#include <bits/stdc++.h>
using namespace std;
const int maxn=1e3+5,maxw=1e4+5;
int n,m,a[maxn],dp[maxw];
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}
	for(int i=1;i<=maxw;i++)
		dp[i]=91781391;
	for(int i=1;i<=n;i++){
		for(int j=a[i];j<=m;j++){
			dp[j]=min(dp[j],dp[j-a[i]]+1);
		}
	}
	cout<<dp[m];
	return 0;
}
